-- procedure sp_create_album
-- -----------------------------------------------------

USE `cs361_photo_catalog`;
DROP procedure IF EXISTS `cs361_photo_catalog`.`sp_create_album`;

DELIMITER $$
USE `cs361_photo_catalog`$$
CREATE PROCEDURE sp_create_album (
	IN p_name varchar(45),
    IN p_folder_id int,
    OUT p_new_album_id int
)
COMMENT 'Add a new album and return album ID'
BEGIN
	IF (p_folder_id IS NULL OR p_folder_id = '') THEN
		INSERT INTO Albums (
			name
		)
		VALUES (
			p_name
		);
    ELSE
		INSERT INTO Albums (
			name,
			folderID
		)
		VALUES (
			p_name,
			p_folder_id
		);
	END IF;

    -- Store the ID of the last inserted row
    SELECT LAST_INSERT_ID() into p_new_album_id;
    -- Display the ID of the last inserted album
    SELECT LAST_INSERT_ID() AS 'new_id';

END$$

DELIMITER ;

