CREATE PROCEDURE sp_import_photo (
    IN p_name varchar(255),
    IN p_path mediumtext,
    IN p_album_id int,
    OUT p_new_photo_id int
)
COMMENT 'Add a new photo and return photo ID'
BEGIN
