DROP TABLE IF EXISTS `cs361_photo_catalog`.`v_all_photos`;
DROP VIEW IF EXISTS `cs361_photo_catalog`.`v_all_photos` ;
USE `cs361_photo_catalog`;
CREATE  OR REPLACE VIEW v_all_photos AS
SELECT
	Albums.name AS Album,
    Photos.photoID AS PhotoID,
    Photos.name AS FileName,
    Photos.path AS FilePath,
    GROUP_CONCAT(IFNULL(Tags.name, '')) AS Tags
FROM
    Albums
    LEFT JOIN Photos ON Albums.albumID = Photos.albumID
    LEFT JOIN PhotoTags ON Photos.photoID = PhotoTags.photoID
    LEFT JOIN Tags ON PhotoTags.tagID = Tags.tagID
GROUP BY Album, PhotoID, FileName, FilePath
ORDER BY Albums.name;

